class HomePage extends StatelessWidget{const HomePage({super.key});void open(BuildContext c,Widget p){play('tap.wav');Navigator.push(c,MaterialPageRoute(builder:(_)=>p));}@override Widget build(BuildContext c)=>Directionality(textDirection:TextDirection.rtl,child:Scaffold(appBar:AppBar(title:const Text('طفلي الأول')),body:SafeArea(child:ListView(padding:const EdgeInsets.all(16),children:[const Text('تعلم والعب',textAlign:TextAlign.center,style:TextStyle(fontSize:36,fontWeight:FontWeight.w900)),const SizedBox(height:14),HomeButton('🇸🇦','العربية',()=>open(c,const ArabicPage())),HomeButton('🇬🇧','English',()=>open(c,const EnglishPage())),HomeButton('🐶','الحيوانات عربي + English',()=>open(c,const LearnGrid(title:'الحيوانات',items:animals,rtl:true))),HomeButton('🎮','الألعاب',()=>open(c,const GamesPage()))]))));}
