class GamesPage extends StatefulWidget{const GamesPage({super.key});@override State<GamesPage> createState()=>_GamesPageState();}
class _GamesPageState extends State<GamesPage>{int stars=0;String msg='اختر الأسد';void ans(bool ok){play(ok?'success.wav':'wrong.wav');setState((){if(ok){stars++;msg='أحسنت ⭐';}else{msg='حاول مرة أخرى';}});}@override Widget build(BuildContext c){final opts=animals.take(4).toList();return Directionality(textDirection:TextDirection.rtl,child:Scaffold(appBar:AppBar(title:Text('الألعاب  ⭐ $stars')),body:Padding(padding:const EdgeInsets.all(16),child:Column(children:[Text(msg,textAlign:TextAlign.center,style:const TextStyle(fontSize:30,fontWeight:FontWeight.w900)),const SizedBox(height:18),Expanded(child:GridView.builder(itemCount:opts.length,gridDelegate:const SliverGridDelegateWithFixedCrossAxisCount(crossAxisCount:2,mainAxisSpacing:12,crossAxisSpacing:12),itemBuilder:(_,i){final it=opts[i];return Card(color:Colors.white,shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(26)),child:InkWell(borderRadius:BorderRadius.circular(26),onTap:()=>ans(it.title=='أسد'),child:Center(child:Text(it.emoji,style:const TextStyle(fontSize:74)))));}))]))));}}
